<script lang='ts'>import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminBilling, type AdminBilling} from '$lib/api';let d:AdminBilling|null=null;let error='';const load=async()=>{try{d=await fetchAdminBilling();}catch(e:any){error=e.message||'Erreur';}};onMount(load);</script><AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<button on:click={load}>Refresh</button>{#if error}<p>{error}</p>{/if}{#if d}<p>Total {d?.subscriptions?.total??0} Active {d?.subscriptions?.active??0} Inactive {d?.subscriptions?.inactive??0}</p><p>MRR {(d?.mrr?.estimate_cents??0)/100}</p><p>MRR estimé à partir des plans internes. Ce n’est pas une source comptable officielle Stripe.</p>{/if}{/if}</AppShell>
